const raw = {};
for (const item of $input.all()) {
  raw[item.json.key] = item.json.value;
}

const env = {
  mode: raw.mode,
  is_live: raw.mode === 'live',
  script_approval_required: raw.script_approval_required === 'true',
  evrm_token: raw.evrm_token,
  pdfshift_api_key: raw.pdfshift_api_key || '',
  qr_code_url: raw.qr_code_url || '',
  supabase_url: raw.supabase_url || '',
  supabase_storage_url: raw.supabase_storage_url || '',
  supabase_service_key: raw.supabase_service_key || '',
  feedback_form_url: raw.feedback_form_url || ''
