function injectVars(html, variables) {
    let result = html;
    for (const [key, value] of Object.entries(variables)) {
        const regex = new RegExp(`\\{\\{${key.replace(/\./g, '\\.')}\\}\\}`, 'g');
        result = result.replace(regex, value);
    }
    return result;
}

