const pdfBase = `${storageBase}/${bucket}/pdfs/${order.order_id}`;
const storybookUrl = `${pdfBase}/storybook.pdf?download=EverMagic-Storybook.pdf`;
const coloringBookUrl = `${pdfBase}/coloring_book.pdf?download=EverMagic-Coloring-Book.pdf`;
const certificateUrl = `${pdfBase}/certificate.pdf?download=EverMagic-Certificate.pdf`;

// Story title
const storyTitle = scriptContent.title || `${child.name}'s Space Adventure`;

// Thank-you message shown on page and in email
const thankYouMessage = `Your story is here — all three files are ready to save and treasure. `
    + `We hope ${child.name} loves every moment of the adventure! 🚀`;

// ─────────────────────────────────────────────────────────────
// 2. Populate templates
// ─────────────────────────────────────────────────────────────

const branch = env.is_live ? 'main' : 'develop';
const logoUrl = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/templates/icons/logo_email.png`;

const emailVars = {
    'logo_url': logoUrl,
    'child_name': child.name,
    'story_title': storyTitle,
    'thank_you_message': thankYouMessage,
    'storybook_url': storybookUrl,
    'coloring_book_url': coloringBookUrl,
    'certificate_url': certificateUrl,
};

function injectVars(html, vars) {
    let result = html;
    for (const [key, value] of Object.entries(vars)) {
        const regex = new RegExp(`\\{\\{${key.replace(/\./g, '\\.')}\\}\\}`, 'g');
        result = result.replace(regex, value);
    }
    return result;
}

const emailTemplate = $('Fetch Delivery Email Template').first().json.data;
const customerEmailHtml = injectVars(emailTemplate, emailVars);

// ─────────────────────────────────────────────────────────────
// 3. Admin notification (plain HTML — no separate template needed)
// ─────────────────────────────────────────────────────────────

const adminEmailHtml = `
<div style="font-family:monospace; padding:20px;">
  <h2>✅ Order Delivered — ${order.order_id}</h2>
  <p><strong>Child:</strong> ${child.name}, age ${child.age}</p>
  <p><strong>Story:</strong> ${storyTitle}</p>
  <p><strong>Customer email:</strong> ${order.delivery.email}</p>
  <hr>
  <p>PDFs:<br>
    📖 <a href="${storybookUrl}">Storybook</a><br>
    🎨 <a href="${coloringBookUrl}">Coloring Book</a><br>
    🏅 <a href="${certificateUrl}">Certificate</a>
  </p>
</div>
`.trim();

// ─────────────────────────────────────────────────────────────
// 4. Return
// ─────────────────────────────────────────────────────────────

return [{
    json: {
        order_id: order.order_id,
        child_name: child.name,
        child_email: order.delivery.email,

        customer_email_html: customerEmailHtml,
        customer_email_subject: `✨ ${child.name}'s magic is ready — download your files!`,

        admin_email_html: adminEmailHtml,
        admin_email_subject: `✅ Delivered — ${order.order_id} — ${child.name}`,
    }
}];

const deliveryData = $('Build Delivery').first().json;
const env          = $('Envs').first().json.env;

const feedbackFormBase = env.feedback_form_url;
if (!feedbackFormBase) throw new Error('Missing env: feedback_form_url');

const feedbackUrl = feedbackFormBase
  + `?order_id=${encodeURIComponent(deliveryData.order_id)}`
  + `&email=${encodeURIComponent(deliveryData.child_email)}`;

const branch  = env.is_live ? 'main' : 'develop';
const logoUrl = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/templates/icons/logo_email.png`;

const template = $('Fetch Feedback Request Email Template').first().json.data;

const html = template
  .replace(/\{\{logo_url\}\}/g,     logoUrl)
  .replace(/\{\{child_name\}\}/g,   deliveryData.child_name)
  .replace(/\{\{feedback_url\}\}/g, feedbackUrl);

return [{
  json: {
    to:      deliveryData.child_email,
    subject: `${deliveryData.child_name}'s files are ready — quick feedback? Taras`,
    html,
  }
}];

const payload = JSON.parse($('Fetch Order Payload').first().json.payload_json);
  const themeFolder = (payload.theme || 'SPACE_HERO').toLowerCase();
  const branch = $('Envs').first().json.env.is_live ? 'main' : 'develop';
  const url = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/prompts/${themeFolder}/theme_styles.css`;
  return [{ json: { url } }];
